import React, { Component } from "react";
import "@google/model-viewer";

class Viewer extends Component {
  render() {
    return (
      <div style={{ height: "80vh", width: "100vw" }}>
        <model-viewer
          style={{ height: "80vh", width: "100vw" }}
          src="../../static/Astronaut.glb"
        ></model-viewer>
      </div>
    );
  }
}

export default Viewer;
